mapper.delete:
/* adm-file-sql-oracle.xml -deleteFileInfo */
	DELETE
		FROM TADMIN_MST_FILE
	 WHERE FILEKEY = #{filekey}
	   AND FILESEQ = #{fileseq}

mapper.insert:
	/* adm-file-sql-oracle.xml - insertFileInfo */
		INSERT INTO TADMIN_MST_FILE
		(
		       FILEKEY
		     , FILESEQ
		     , APKEY
		     , MEKEY
		     , FILEPATH
		     , FILESIZE
		     , FILEEXTS
		     , ORIGFILENM
		     , SAVEFILENM
		     , REM
		     , INSERTDATE
		     , INSERTURKEY
		     , UPDATEDATE
		     , UPDATEURKEY
		)
		VALUES
		(
		       #{filekey}
			 , #{fileseq}
			 , #{apkey}
			 , #{mekey}
			 , #{filepath}
			 , #{filesize}
			 , #{fileexts}
			 , #{origfilenm}
			 , #{savefilenm}
			 , #{rem}
   			 , #{sysdate}
			 , #{surkey}
			 , #{sysdate}
			 , #{surkey}
		)

